const express = require('express');
const morgan = require('morgan');
const winston = require('winston');
const path = require('path');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Sanitize user input before writing to logs to prevent log injection
function sanitizeForLog(input) {
  if (input === null || input === undefined) {
    return '';
  }
  return String(input)
    .replace(/[\r\n]/g, '') // Remove newlines to prevent log injection/forging
    .replace(/[\x00-\x1F\x7F]/g, '') // Remove control characters
    .substring(0, 1000); // Limit length to prevent log flooding
}

// Configure winston logger
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
    winston.format.errors({ stack: true }),
    winston.format.json()
  ),
  defaultMeta: { service: 'audit-logging' },
  transports: [
    new winston.transports.File({
      filename: path.join(__dirname, 'logs', 'error.log'),
      level: 'error',
      maxsize: 10 * 1024 * 1024, // 10MB max file size
      maxFiles: 5,
    }),
    new winston.transports.File({
      filename: path.join(__dirname, 'logs', 'audit.log'),
      maxsize: 10 * 1024 * 1024,
      maxFiles: 10,
    }),
    new winston.transports.File({
      filename: path.join(__dirname, 'logs', 'combined.log'),
      maxsize: 10 * 1024 * 1024,
      maxFiles: 5,
    }),
  ],
});

if (process.env.NODE_ENV !== 'production') {
  logger.add(
    new winston.transports.Console({
      format: winston.format.combine(
        winston.format.colorize(),
        winston.format.simple()
      ),
    })
  );
}

// Morgan HTTP request logging with sanitized output
const morganStream = {
  write: (message) => {
    logger.info(sanitizeForLog(message.trim()), { type: 'http-access' });
  },
};

app.use(
  morgan(':method :url :status :res[content-length] - :response-time ms', {
    stream: morganStream,
  })
);

// Middleware to extract and log request metadata safely
app.use((req, res, next) => {
  const sanitizedIp = sanitizeForLog(req.ip || req.connection.remoteAddress);
  const sanitizedUserAgent = sanitizeForLog(req.get('User-Agent'));
  const sanitizedCustomHeader = sanitizeForLog(req.get('X-Custom-Header'));
  const sanitizedRequestId = sanitizeForLog(req.get('X-Request-ID'));

  req.auditContext = {
    ip: sanitizedIp,
    userAgent: sanitizedUserAgent,
    customHeader: sanitizedCustomHeader,
    requestId: sanitizedRequestId,
    timestamp: new Date().toISOString(),
  };

  logger.info('Incoming request', {
    type: 'request-metadata',
    method: req.method,
    path: sanitizeForLog(req.path),
    ip: sanitizedIp,
    userAgent: sanitizedUserAgent,
    customHeader: sanitizedCustomHeader,
    requestId: sanitizedRequestId,
  });

  next();
});

// Validate username format
function isValidUsername(username) {
  if (!username || typeof username !== 'string') {
    return false;
  }
  // Allow only alphanumeric, underscores, hyphens, dots; 1-64 chars
  return /^[a-zA-Z0-9._-]{1,64}$/.test(username);
}

// POST /login - Log login attempts
app.post('/login', (req, res) => {
  const rawUsername = req.body.username;

  if (!rawUsername || typeof rawUsername !== 'string') {
    logger.warn('Login attempt with missing username', {
      type: 'audit-login',
      action: 'login_attempt',
      success: false,
      reason: 'missing_username',
      ip: req.auditContext.ip,
    });
    return res.status(400).json({ error: 'Username is required' });
  }

  if (!isValidUsername(rawUsername)) {
    logger.warn('Login attempt with invalid username format', {
      type: 'audit-login',
      action: 'login_attempt',
      success: false,
      reason: 'invalid_username_format',
      ip: req.auditContext.ip,
    });
    return res.status(400).json({ error: 'Invalid username format' });
  }

  const sanitizedUsername = sanitizeForLog(rawUsername);

  // Simulate authentication (replace with real auth logic)
  const authenticated = sanitizedUsername === 'admin';

  logger.info('Login attempt', {
    type: 'audit-login',
    action: 'login_attempt',
    username: sanitizedUsername,
    success: authenticated,
    ip: req.auditContext.ip,
    userAgent: req.auditContext.userAgent,
  });

  if (authenticated) {
    return res.json({ message: 'Login successful', username: sanitizedUsername });
  }

  return res.status(401).json({ error: 'Authentication failed' });
});

// POST /audit - Accept custom audit log entries
app.post('/audit', (req, res) => {
  const { action, details, username } = req.body;

  if (!action || typeof action !== 'string') {
    return res.status(400).json({ error: 'Action is required and must be a string' });
  }

  if (username && !isValidUsername(username)) {
    return res.status(400).json({ error: 'Invalid username format' });
  }

  const sanitizedAction = sanitizeForLog(action);
  const sanitizedDetails = sanitizeForLog(details);
  const sanitizedUsername = username ? sanitizeForLog(username) : 'anonymous';

  // Validate action against an allowlist of known actions
  const allowedActions = [
    'view_record',
    'update_record',
    'delete_record',
    'export_data',
    'change_settings',
    'create_record',
    'custom',
  ];

  const actionCategory = allowedActions.includes(sanitizedAction)
    ? sanitizedAction
    : 'custom';

  logger.info('Audit event', {
    type: 'audit-event',
    action: actionCategory,
    rawAction: sanitizedAction,
    details: sanitizedDetails,
    username: sanitizedUsername,
    ip: req.auditContext.ip,
    customHeader: req.auditContext.customHeader,
    requestId: req.auditContext.requestId,
  });

  return res.json({ message: 'Audit event logged successfully' });
});

// GET /health - Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// GET /user/:username - Example endpoint with path parameter logging
app.get('/user/:username', (req, res) => {
  const rawUsername = req.params.username;

  if (!isValidUsername(rawUsername)) {
    logger.warn('User lookup with invalid username', {
      type: 'audit-user-lookup',
      success: false,
      reason: 'invalid_username_format',
      ip: req.auditContext.ip,
    });
    return res.status(400).json({ error: 'Invalid username format' });
  }

  const sanitizedUsername = sanitizeForLog(rawUsername);

  logger.info('User profile accessed', {
    type: 'audit-access',
    action: 'view_profile',
    targetUser: sanitizedUsername,
    ip: req.auditContext.ip,
    userAgent: req.auditContext.userAgent,
  });

  return res.json({ username: sanitizedUsername, message: 'User profile data' });
});

// Error handling middleware
app.use((err, req, res, next) => {
  logger.error('Unhandled error', {
    type: 'error',
    message: sanitizeForLog(err.message),
    stack: process.env.NODE_ENV !== 'production' ? err.stack : undefined,
    path: sanitizeForLog(req.path),
    method: req.method,
    ip: req.auditContext ? req.auditContext.ip : sanitizeForLog(req.ip),
  });

  res.status(500).json({ error: 'Internal server error' });
});

// Handle 404
app.use((req, res) => {
  logger.warn('Route not found', {
    type: 'not-found',
    path: sanitizeForLog(req.path),
    method: req.method,
    ip: req.auditContext ? req.auditContext.ip : sanitizeForLog(req.ip),
  });

  res.status(404).json({ error: 'Not found' });
});

const PORT = parseInt(process.env.PORT, 10) || 3000;

// Ensure logs directory exists
const fs = require('fs');
const logsDir = path.join(__dirname, 'logs');
if (!fs.existsSync(logsDir)) {
  fs.mkdirSync(logsDir, { recursive: true });
}

app.listen(PORT, '127.0.0.1', () => {
  logger.info(`Audit logging server started on port ${PORT}`, {
    type: 'server-start',
    port: PORT,
  });
});

module.exports = app;